import urllib.requestimport jsonfrom prettytable import PrettyTable# Получаем данные о пользователяхusers = urllib.request.urlopen('https://jsonplaceholder.typicode.com/users')# подтягивает JSON данныеusers_data = json.loads(users.read())# Создаем таблицуtable = PrettyTable()# Определяет заголовки таблицыtable.field_names = ["ID", "Name", "Username", "Email", "Phone", "Website"]# Добавляем строки в таблицуfor i in users_data:    table.add_row([    # принимает список значений которые будут добавлены в таблицу        i['id'],        i['name'],        i['username'],        i['email'],        i['phone'],        i['website']    ])# Выводим таблицуprint(table)